import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const CATEGORIES = ['All', 'Healthcare', 'Beauty', 'Consulting', 'Fitness', 'Education', 'Home Services'];

const SERVICE_ICONS = {
  Healthcare: '🏥', Beauty: '💅', Consulting: '💼',
  Fitness: '💪', Education: '📚', 'Home Services': '🏠', Default: '⭐'
};

export default function Home() {
  const [services, setServices] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [category, setCategory] = useState('All');
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    API.get('/services').then(res => {
      setServices(res.data);
      setFiltered(res.data);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  useEffect(() => {
    let result = services;
    if (category !== 'All') result = result.filter(s => s.category === category);
    if (search) result = result.filter(s => s.name.toLowerCase().includes(search.toLowerCase()) || s.description?.toLowerCase().includes(search.toLowerCase()));
    setFiltered(result);
  }, [category, search, services]);

  const stats = [
    { label: 'Services Available', value: services.length + '+', icon: '🎯' },
    { label: 'Happy Customers', value: '500+', icon: '😊' },
    { label: 'Expert Providers', value: '50+', icon: '👨‍💼' },
    { label: 'Cities Covered', value: '10+', icon: '🌆' },
  ];

  return (
    <div style={{ minHeight: '100vh', background: '#0f0f1a' }}>

      {/* Hero */}
      <div style={{
        minHeight: '100vh', display: 'flex', flexDirection: 'column',
        justifyContent: 'center', alignItems: 'center', textAlign: 'center',
        padding: '100px 20px 60px',
        background: 'radial-gradient(ellipse at top, rgba(99,102,241,0.15) 0%, transparent 60%), radial-gradient(ellipse at bottom right, rgba(168,85,247,0.1) 0%, transparent 50%)',
        position: 'relative', overflow: 'hidden'
      }}>
        {/* Floating circles */}
        {[...Array(5)].map((_, i) => (
          <div key={i} style={{
            position: 'absolute',
            width: `${80 + i * 40}px`, height: `${80 + i * 40}px`,
            borderRadius: '50%',
            border: '1px solid rgba(99,102,241,0.1)',
            top: `${10 + i * 15}%`, left: `${5 + i * 20}%`,
            animation: `float ${3 + i}s ease-in-out infinite`,
            animationDelay: `${i * 0.5}s`
          }} />
        ))}

        <div style={{ animation: 'slide-in 0.8s ease' }}>
          <div style={{
            display: 'inline-block', padding: '6px 20px', borderRadius: '20px',
            background: 'rgba(159, 219, 239, 0.15)', border: '1px solid rgba(99,102,241,0.3)',
            color: '#a855f7', fontSize: '13px', fontWeight: 600, marginBottom: '24px'
          }}>✨ #1 Appointment Booking Platform</div>

          <h1 style={{ fontSize: 'clamp(36px, 6vw, 72px)', fontWeight: 900, lineHeight: 1.1, marginBottom: '20px' }}>
            Book Your <span className="gradient-text">Perfect</span><br />Appointment Today
          </h1>
          <p style={{ fontSize: '18px', color: 'rgba(255,255,255,0.6)', maxWidth: '560px', margin: '0 auto 40px', lineHeight: 1.6 }}>
            Connect with top-rated service providers. Healthcare, beauty, fitness, consulting and more — all in one place.
          </p>

          <div style={{ display: 'flex', gap: '16px', justifyContent: 'center', flexWrap: 'wrap' }}>
            {!user ? (
              <>
                <button className="btn-primary" onClick={() => navigate('/register')} style={{ fontSize: '16px', padding: '14px 32px' }}>
                  Get Started Free →
                </button>
                <button className="btn-secondary" onClick={() => navigate('/login')} style={{ fontSize: '16px', padding: '14px 32px' }}>
                  Sign In
                </button>
              </>
            ) : (
              <button className="btn-primary" onClick={() => document.getElementById('services').scrollIntoView({ behavior: 'smooth' })} style={{ fontSize: '16px', padding: '14px 32px' }}>
                Browse Services ↓
              </button>
            )}
          </div>
        </div>

        {/* Stats */}
        <div style={{ display: 'flex', gap: '24px', marginTop: '80px', flexWrap: 'wrap', justifyContent: 'center' }}>
          {stats.map((s, i) => (
            <div key={i} className="glass" style={{ padding: '20px 28px', textAlign: 'center', minWidth: '130px', animation: `slide-in 0.5s ease ${0.2 + i * 0.1}s both` }}>
              <div style={{ fontSize: '28px', marginBottom: '4px' }}>{s.icon}</div>
              <div style={{ fontSize: '24px', fontWeight: 800, background: 'linear-gradient(135deg, #6366f1, #a855f7)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>{s.value}</div>
              <div style={{ fontSize: '12px', color: 'rgba(255,255,255,0.5)', marginTop: '2px' }}>{s.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Services Section */}
      <div id="services" style={{ padding: '80px 40px', maxWidth: '1200px', margin: '0 auto' }}>
        <div style={{ textAlign: 'center', marginBottom: '50px' }}>
          <h2 style={{ fontSize: '42px', fontWeight: 800, marginBottom: '12px' }}>
            Available <span className="gradient-text">Services</span>
          </h2>
          <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '16px' }}>Choose from our wide range of professional services</p>
        </div>

        {/* Search & Filter */}
        <div style={{ display: 'flex', gap: '16px', marginBottom: '32px', flexWrap: 'wrap' }}>
          <input
            className="input-field"
            placeholder="🔍 Search services..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={{ flex: 1, minWidth: '200px' }}
          />
        </div>

        <div style={{ display: 'flex', gap: '10px', marginBottom: '40px', flexWrap: 'wrap' }}>
          {CATEGORIES.map(cat => (
            <button key={cat} onClick={() => setCategory(cat)} style={{
              padding: '8px 20px', borderRadius: '20px', border: 'none', cursor: 'pointer',
              fontWeight: 600, fontSize: '13px', transition: 'all 0.3s',
              background: category === cat ? 'linear-gradient(135deg, #6366f1, #a855f7)' : 'rgba(255,255,255,0.07)',
              color: category === cat ? '#fff' : 'rgba(255,255,255,0.6)',
              transform: category === cat ? 'scale(1.05)' : 'scale(1)',
              boxShadow: category === cat ? '0 4px 15px rgba(99,102,241,0.4)' : 'none'
            }}>{cat}</button>
          ))}
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '60px', color: 'rgba(255,255,255,0.4)' }}>
            <div style={{ fontSize: '40px', animation: 'float 1s infinite' }}>⏳</div>
            <p style={{ marginTop: '12px' }}>Loading services...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px' }}>
            <div style={{ fontSize: '60px' }}>🔍</div>
            <p style={{ color: 'rgba(255,255,255,0.4)', marginTop: '16px', fontSize: '18px' }}>No services found</p>
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '24px' }}>
            {filtered.map((s, i) => (
              <ServiceCard key={s._id} service={s} index={i} onBook={() => user ? navigate(`/book/${s._id}`) : navigate('/login')} />
            ))}
          </div>
        )}
      </div>

      {/* CTA Section */}
      {!user && (
        <div style={{
          margin: '40px', borderRadius: '24px', padding: '60px',
          background: 'linear-gradient(135deg, rgba(99,102,241,0.2), rgba(168,85,247,0.2))',
          border: '1px solid rgba(99,102,241,0.3)', textAlign: 'center'
        }}>
          <h2 style={{ fontSize: '36px', fontWeight: 800, marginBottom: '16px' }}>Ready to Get Started?</h2>
          <p style={{ color: 'rgba(255,255,255,0.6)', marginBottom: '32px', fontSize: '16px' }}>Join thousands of happy customers booking services daily.</p>
          <div style={{ display: 'flex', gap: '16px', justifyContent: 'center', flexWrap: 'wrap' }}>
            <button className="btn-primary" onClick={() => navigate('/register?role=customer')} style={{ fontSize: '15px', padding: '14px 28px' }}>
              👤 Book as Customer
            </button>
            <button className="btn-secondary" onClick={() => navigate('/register?role=provider')} style={{ fontSize: '15px', padding: '14px 28px' }}>
              🏪 Join as Provider
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function ServiceCard({ service, index, onBook }) {
  const icon = SERVICE_ICONS[service.category] || SERVICE_ICONS.Default;
  return (
    <div className="glass card-hover" style={{ padding: '24px', cursor: 'pointer', animation: `slide-in 0.5s ease ${index * 0.08}s both` }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
        <div style={{
          width: 52, height: 52, borderRadius: '14px', fontSize: '26px',
          background: 'linear-gradient(135deg, rgba(99,102,241,0.2), rgba(168,85,247,0.2))',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          border: '1px solid rgba(99,102,241,0.2)'
        }}>{icon}</div>
        {service.category && (
          <span style={{ fontSize: '11px', padding: '4px 10px', borderRadius: '20px', background: 'rgba(168,85,247,0.15)', color: '#a855f7', border: '1px solid rgba(168,85,247,0.2)' }}>
            {service.category}
          </span>
        )}
      </div>
      <h3 style={{ fontSize: '18px', fontWeight: 700, marginBottom: '8px', color: '#fff' }}>{service.name}</h3>
      <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '13px', marginBottom: '16px', lineHeight: 1.5 }}>{service.description || 'Professional service available for booking.'}</p>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
        <span style={{ color: 'rgba(255,255,255,0.5)', fontSize: '13px' }}>⏱ {service.duration} mins</span>
        <span style={{ fontSize: '20px', fontWeight: 800, background: 'linear-gradient(135deg, #6366f1, #a855f7)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>₹{service.price}</span>
      </div>
      <div style={{ fontSize: '12px', color: 'rgba(255,255,255,0.4)', marginBottom: '16px' }}>👤 {service.provider?.name}</div>
      <button className="btn-primary" onClick={onBook} style={{ width: '100%', padding: '11px' }}>Book Now →</button>
    </div>
  );
}
